// --- VIEW ONLY & GUEST MODE BLOCKER ---
const checkBlock = () => {
    if (window._isReadOnlyMode) {
        alert("View Only Mode: Changes are blocked because your account is actively used on another device.");
        throw new Error("Read-Only Mode Blocked Action");
    }
    if (window.isGuestMode) {
        if (window.guestTxCount >= (window.guestTxLimit || 15)) {
            alert(`Guest Mode Limit Reached: You have created/edited ${window.guestTxLimit || 15} transactions. Please login or activate a license to continue.`);
            throw new Error("Guest Limit Reached");
        }
    }
};

const incrementGuestCount = () => {
    if (window.isGuestMode) {
        window.guestTxCount = (window.guestTxCount || 0) + 1;
        console.log(`[Guest Mode] Tx Counter: ${window.guestTxCount}/${window.guestTxLimit || 15}`);
    }
};

const addDoc = async (...args) => { checkBlock(); const res = await fAddDoc(...args); incrementGuestCount(); return res; };
const updateDoc = async (...args) => { checkBlock(); const res = await fUpdateDoc(...args); incrementGuestCount(); return res; };
const setDoc = async (...args) => { checkBlock(); const res = await fSetDoc(...args); incrementGuestCount(); return res; };
const deleteDoc = (...args) => { checkBlock(); return fDeleteDoc(...args); };
const writeBatch = (...args) => { checkBlock(); return fWriteBatch(...args); };
const runTransaction = (...args) => { checkBlock(); return fRunTransaction(...args); };
const httpsCallable = (...args) => {
    const fn = fHttpsCallable(...args);
    return (data) => { checkBlock(); return fn(data); };
};

