// Helper for Column Names (A, B, ... AA, AB) without needing jspreadsheet lib
const getColumnName = (index) => {
    let columnName = "";
    while (index >= 0) {
        columnName = String.fromCharCode(65 + (index % 26)) + columnName;
        index = Math.floor(index / 26) - 1;
    }
    return columnName;
};

const toDateObject = (value) => {
    if (!value) return null;
    if (typeof value?.toDate === 'function') return value.toDate();
    if (value instanceof Date) return value;
    if (typeof value === 'number') return new Date(value);
    if (typeof value === 'string') {
        if (value.includes('T')) return new Date(value);
        return new Date(`${value}T00:00:00`);
    }
    return null;
};

const format3_global = (num) => Number(num || 0).toLocaleString(undefined, { minimumFractionDigits: 3, maximumFractionDigits: 3 });

const round3 = (val) => {

    const n = Number(val || 0);
    if (isNaN(n)) return 0;
    return Math.round(n * 1000) / 1000;
};

const toQtyNum = (val) => {
    if (typeof val === 'string') {
        const cleaned = val.replace(/,/g, '').trim();
        const parsed = Number(cleaned);
        return Number.isNaN(parsed) ? 0 : round3(parsed);
    }
    const parsed = Number(val);
    return Number.isNaN(parsed) ? 0 : round3(parsed);
};


const formatQtyInOut = (qtyIn, qtyOut, netOverride) => {
    const hasOverride = netOverride !== undefined && netOverride !== null && !Number.isNaN(Number(typeof netOverride === 'string' ? netOverride.replace(/,/g, '') : netOverride));
    const netQty = hasOverride ? toQtyNum(netOverride) : (toQtyNum(qtyIn) - toQtyNum(qtyOut));
    if (netQty === 0) return '-';
    if (netQty < 0) return `(${format3_global(Math.abs(netQty))})`;
    return format3_global(netQty);
};

