// Convert YYYY-MM-DD to DD/MM/YYYY for display
const formatDate = (dateString) => {
    if (!dateString) return "-";
    const [year, month, day] = dateString.split("-");
    return `${day}/${month}/${year}`;
};

// Convert DD/MM/YYYY to YYYY-MM-DD for storage
const parseDisplayDate = (displayDate) => {
    if (!displayDate) return "";
    const [day, month, year] = displayDate.split("/");
    if (!day || !month || !year) return "";
    return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
};



// --- CURRENCY FORMATTER HELPER ---
const formatCurrency = (amount) => Number(amount || 0).toLocaleString('en-US', { minimumFractionDigits: 3, maximumFractionDigits: 3 });

// --- GLOBAL PRECISION SETTING ---
let GLOBAL_QTY_PRECISION = 3;

// UPDATED to use Global Precision (applies everywhere)
const formatQty = (qty) => Number(qty || 0).toLocaleString('en-US', { minimumFractionDigits: GLOBAL_QTY_PRECISION, maximumFractionDigits: GLOBAL_QTY_PRECISION });

// --- AUDIT DATE HELPER ---
const formatAuditDate = (timestamp) => {
    if (!timestamp) return '-';
    // Handle Firestore Timestamp object
    if (timestamp.seconds) return new Date(timestamp.seconds * 1000).toLocaleString();
    // Handle standard Date object or string
    return new Date(timestamp).toLocaleString();
};

// --- DUPLICATE CHECK HELPER ---
const checkDuplicateRef = async (db, collectionName, refNo, userId, excludeId = null) => {
    if (!refNo || !refNo.trim()) return false;

    const q = query(
        collection(db, collectionName),
        where("refNo", "==", refNo.trim()),
        where("userId", "==", userId)
    );

    const snap = await getDocs(q);
    if (snap.empty) return false;
    if (excludeId) {
        // If updating, ignore self
        return snap.docs.some(doc => doc.id !== excludeId);
    }
    return true;
};

// 🔥 GLOBAL DUPLICATE CHECK (Ref No must be unique across ALL Vouchers)
const checkGlobalDuplicate = async (db, refNo, userId, excludeId = null) => {
    if (!refNo || !refNo.trim()) return false;
    const r = refNo.trim();
    // Collections to check
    const cols = ['invoices', 'payments', 'journal_vouchers', 'stock_journals'];

    for (const col of cols) {
        const q = query(collection(db, col), where("refNo", "==", r), where("userId", "==", userId));
        const snap = await getDocs(q);
        if (!snap.empty) {
            if (excludeId) {
                // If even one found matching doc is NOT our self, it's a dupe
                const isDupe = snap.docs.some(d => d.id !== excludeId);
                if (isDupe) return true;
            } else {
                return true;
            }
        }
    }
    return false;
};

// 🔥 CONTAINER DUPLICATE CHECK (Invoices Only)
const checkDuplicateContainer = async (db, containerNo, userId, excludeId = null) => {
    if (!containerNo || !containerNo.trim()) return false;
    const c = containerNo.trim();
    const q = query(collection(db, 'invoices'), where("containerNo", "==", c), where("userId", "==", userId));
    const snap = await getDocs(q);
    if (!snap.empty) {
        if (excludeId) return snap.docs.some(d => d.id !== excludeId);
        return true;
    }
    return false;
};
// --- UPDATED SEARCHABLE SELECT (With Ref, Shortcuts & Portal for Front Layer) ---
const SearchableSelect = React.forwardRef(({ 
    options, groups, value, onChange, placeholder, label, required, 
    warningIfEmpty, onCreateNew, compact, containerClassName, textClassName, triggerClassName 
}, ref) => {
    const [isOpen, setIsOpen] = useState(false);
    const [search, setSearch] = useState("");
    const [activeGroup, setActiveGroup] = useState('ALL'); // For grouped mode
    const [highlightedIndex, setHighlightedIndex] = useState(0);

    const wrapperRef = useRef(null);
    const dropdownRef = useRef(null);
    const inputRef = useRef(null);
    const optionRefs = useRef([]);

    // Combine internal wrapperRef with external ref
    React.useImperativeHandle(ref, () => wrapperRef.current);

    // 1. Flatten options if groups are provided
    const effectiveOptions = useMemo(() => {
        if (groups && groups.length > 0) {
            return groups.flatMap(g => g.options.map(o => ({ ...o, group: g.name })));
        }
        return options || [];
    }, [groups, options]);

    // 2. Filter Logic
    const filteredOptions = effectiveOptions.filter(opt => {
        const matchesSearch = (opt.text || "").toLowerCase().includes(search.toLowerCase());
        const matchesGroup = activeGroup === 'ALL' || (groups ? opt.group === activeGroup : true);
        return matchesSearch && matchesGroup;
    });

    const selectedOption = effectiveOptions.find(opt => opt.value === value);

    // Auto-switch group if value matches (when opening)
    useEffect(() => {
        if (isOpen && selectedOption && selectedOption.group && groups) {
            setActiveGroup(selectedOption.group);
        } else if (isOpen && groups) {
            setActiveGroup('ALL'); // Reset to ALL on fresh open
        }
    }, [isOpen, selectedOption, groups]);

    // Sync highlightedIndex with value when it changes, but ONLY reset if necessary
    useEffect(() => {
        if (!isOpen) return;
        const selectedIndex = filteredOptions.findIndex((opt) => opt.value === value);
        if (selectedIndex >= 0) {
            setHighlightedIndex(selectedIndex);
        } else {
            // Only reset if it's out of bounds or search changed
            if (highlightedIndex >= filteredOptions.length) {
                setHighlightedIndex(0);
            }
        }
    }, [isOpen, search, activeGroup, value]); // Removed filteredOptions from dependency to prevent jumping on background data updates

    useEffect(() => {
        if (!isOpen) return;
        const node = optionRefs.current[highlightedIndex];
        if (node && typeof node.scrollIntoView === 'function') {
            node.scrollIntoView({ block: 'nearest' });
        }
    }, [highlightedIndex, isOpen]);

    // Handle clicks outside (Wrapper OR Dropdown) - Now for the modal backdrop
    const handleBackdropClick = (e) => {
        if (e.target === e.currentTarget) {
            setIsOpen(false);
        }
    };

    // Auto-focus input when opened
    useEffect(() => {
        if (isOpen && inputRef.current) {
            // Small timeout to ensure render
            setTimeout(() => inputRef.current?.focus(), 50);
        }
    }, [isOpen]);

    const selectOption = (opt, e) => {
        if (e) {
            e.preventDefault();
            e.stopPropagation();
        }
        if (!opt) return;
        onChange(opt.value, opt);
        setIsOpen(false);
        setSearch("");
        setHighlightedIndex(0);
        if (wrapperRef.current) wrapperRef.current.focus();
    };

    const handleKeyDown = (e) => {
        // Ctrl+C to create new
        if ((e.ctrlKey || e.altKey) && e.key.toLowerCase() === 'c') {
            if (onCreateNew) {
                e.preventDefault();
                setIsOpen(false);
                onCreateNew();
            }
        }
        if ((e.key === 'ArrowDown' || e.key === 'ArrowUp') && !isOpen) {
            e.preventDefault();
            setIsOpen(true);
            return;
        }
        if (e.key === 'ArrowDown' && isOpen) {
            e.preventDefault();
            setHighlightedIndex((prev) => Math.min(prev + 1, Math.max(filteredOptions.length - 1, 0)));
            return;
        }
        if (e.key === 'ArrowUp' && isOpen) {
            e.preventDefault();
            setHighlightedIndex((prev) => Math.max(prev - 1, 0));
            return;
        }
        if (e.key === 'Tab' && isOpen) {
            setIsOpen(false);
            setSearch("");
            return;
        }
        // Enter key to open/select
        if (e.key === 'Enter' && !isOpen) {
            e.preventDefault();
            setIsOpen(true);
            return;
        }
        if (e.key === 'Enter' && isOpen) {
            e.preventDefault();
            e.stopPropagation();
            selectOption(filteredOptions[highlightedIndex], e);
            return;
        }
        // Escape to close
        if (e.key === 'Escape' && isOpen) {
            e.preventDefault();
            e.stopPropagation();
            setIsOpen(false);
            setSearch("");
            wrapperRef.current?.focus();
        }
    };

    const dropdownContent = (
        <div
            className="fixed inset-0 flex items-start justify-center pt-20 bg-black/20 backdrop-blur-[1px]"
            style={{ zIndex: 9999999 }}
            onMouseDown={handleBackdropClick}
        >
            <div
                ref={dropdownRef}
                className="bg-white w-full max-w-lg rounded-xl shadow-2xl border border-gray-200 flex flex-col max-h-[80vh] overflow-hidden animate-in fade-in zoom-in-95 duration-100"
            >
                <div className="p-3 border-b border-gray-100 bg-gray-50 flex flex-col gap-2">
                    <div className="flex items-center gap-2">
                        <Search size={18} className="text-gray-400" />
                        <input
                            ref={inputRef}
                            type="text"
                            className="w-full bg-transparent text-base outline-none text-slate-700 placeholder:text-gray-400 font-medium"
                            placeholder={placeholder || "Search..."}
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            onKeyDown={handleKeyDown}
                        />
                        {onCreateNew && (
                            <button
                                onClick={() => { setIsOpen(false); onCreateNew(); }}
                                className="text-[10px] whitespace-nowrap bg-blue-100 text-blue-700 px-2 py-1 rounded hover:bg-blue-200 font-bold"
                            >
                                + New (Ctrl+C)
                            </button>
                        )}
                    </div>
                    {/* CATEGORY TABS */}
                    {groups && groups.length > 0 && (
                        <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar">
                            <button
                                onClick={() => setActiveGroup('ALL')}
                                className={`px-3 py-1 rounded-full text-[10px] font-bold whitespace-nowrap transition-colors ${activeGroup === 'ALL' ? 'bg-slate-800 text-white' : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-100'}`}
                            >
                                ALL
                            </button>
                            {groups.map(g => (
                                <button
                                    key={g.name}
                                    onClick={() => setActiveGroup(g.name)}
                                    className={`px-3 py-1 rounded-full text-[10px] font-bold whitespace-nowrap transition-colors ${activeGroup === g.name ? 'bg-blue-600 text-white' : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-100'}`}
                                >
                                    {g.name}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                <div className="overflow-y-auto flex-1 p-1">
                    {filteredOptions.length > 0 ? (
                        filteredOptions.map((opt, idx) => (
                            <div
                                key={opt.value + idx}
                                ref={(node) => { optionRefs.current[idx] = node; }}
                                className={`px-4 py-3 text-sm cursor-pointer border-b border-transparent rounded-lg transition-all ${(idx === highlightedIndex || value === opt.value) ? 'bg-blue-50 text-blue-800 font-bold border-blue-100' : 'text-slate-700 hover:bg-blue-50 hover:border-blue-100'}`}
                                onMouseEnter={() => {
                                    if (idx !== highlightedIndex) setHighlightedIndex(idx);
                                }}
                                onClick={(e) => selectOption(opt, e)}
                            >
                                <div className="flex items-center justify-between w-full gap-2">
                                    <span className="truncate">{opt.text}</span>
                                    <div className="flex items-center gap-2 shrink-0">
                                        {opt.badge && <span className={`text-[9px] px-1.5 py-0.5 rounded-full uppercase tracking-wider font-black ${opt.badgeClass || 'bg-slate-100 text-slate-500'}`}>{opt.badge}</span>}
                                        {opt.balance && (
                                            <span className={`text-[10px] font-mono font-bold ${opt.balanceClass || 'text-slate-500'}`}>
                                                {opt.balance}
                                            </span>
                                        )}
                                        {opt.group && <span className="text-[9px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded-full uppercase tracking-wider">{opt.group}</span>}
                                    </div>
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="p-8 text-center text-gray-400 flex flex-col items-center gap-2">
                            <span className="text-sm">No results found for "{search}"</span>
                            {onCreateNew && (
                                <button onClick={() => { setIsOpen(false); onCreateNew(); }} className="text-blue-600 font-bold hover:underline"> Create New? </button>
                            )}
                        </div>
                    )}
                </div>

                <div className="bg-gray-50 p-2 text-[10px] text-gray-400 text-right border-t">
                    Use <b>↑ ↓</b> to navigate, <b>Enter</b> to select, <b>Esc</b> to close
                </div>
            </div>
        </div>
    );

    const activeTextClass = typeof textClassName === 'function' ? textClassName(selectedOption?.text) : (textClassName || '');

    return (
        <div className={`relative mb-2 ${containerClassName || ''}`} ref={wrapperRef} onKeyDown={handleKeyDown} tabIndex={0} style={{ outline: 'none' }}>
            {label && <label className="block text-xs font-semibold text-slate-600 mb-1">{label} {required && "*"}</label>}
            {isOpen && createPortal(dropdownContent, document.body)}

            {(effectiveOptions.length === 0 && warningIfEmpty) ? (
                <div className="w-full p-2 border border-red-300 bg-red-50 rounded-lg text-sm text-red-500 flex items-center gap-2">
                    <AlertTriangle size={14} /> {warningIfEmpty}
                    {onCreateNew && <button onClick={onCreateNew} className="text-xs underline font-bold text-blue-600">Create New (Ctrl+C)</button>}
                </div>
            ) : (
                <div
                    className={`w-full ${compact ? 'p-1.5' : 'p-2'} border rounded-lg text-sm bg-white cursor-pointer flex justify-between items-center ${isOpen ? 'border-blue-500 ring-2 ring-blue-200' : 'border-gray-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200'} ${triggerClassName || ''}`}
                    onClick={() => setIsOpen(!isOpen)}
                >
                    <span className={`truncate overflow-hidden ${selectedOption ? "text-slate-800" : "text-gray-400"} ${activeTextClass}`}>
                        {selectedOption ? selectedOption.text : placeholder || "Select..."}
                    </span>
                    <ChevronDown size={14} className="text-gray-400 shrink-0" />
                </div>
            )}
        </div>
    );
});

// --- LIVE CURRENCY INPUT COMPONENT ---
const CurrencyInput = ({ value, onChange, placeholder, className, disabled }) => {
    // Helper to add commas
    const format = (val) => {
        if (val === undefined || val === null || val === '') return '';
        // Split integer and decimal parts
        const parts = val.toString().split('.');
        // Add commas to integer part
        parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ",");
        return parts.join('.');
    };

    const handleChange = (e) => {
        // 1. Get value and remove existing commas
        let raw = e.target.value.replace(/,/g, '');

        // 2. Allow only numbers and one decimal point
        if (!/^\d*\.?\d*$/.test(raw)) return;

        // 3. Send RAW number back to parent
        onChange(raw);
    };

    return (
        <input
            type="text" // Must be text to allow commas
            className={className}
            placeholder={placeholder}
            value={format(value)} // Show formatted value
            onChange={handleChange}
            disabled={disabled}
        />
    );
};

