    // CRUD Handlers
    const handleDelete = async (collectionName, id) => {
        if (!checkPermission('delete')) return; // Block delete for Data Entry 1

        // 1. CONFIRMATION
        if (!window.confirm("Are you sure you want to delete this record?")) return;

        // 2. SAFETY CHECKS (Referential Integrity)
        try {
            if (collectionName === 'parties') {
                // --- FIX STARTS HERE ---
                // We added: where("userId", "==", user.uid)

                // Check if Party has Invoices
                const invQ = query(
                    collection(db, 'invoices'),
                    where("partyId", "==", id),
                    where("userId", "==", user.uid), // <--- ADDED THIS
                    limit(1)
                );
                const invSnap = await getDocs(invQ);
                if (!invSnap.empty) return alert("❌ ACTION BLOCKED: This Party has existing Invoices. You cannot delete them.");

                // Check if Party has Payments
                const payQ = query(
                    collection(db, 'payments'),
                    where("partyId", "==", id),
                    where("userId", "==", user.uid), // <--- ADDED THIS
                    limit(1)
                );
                const paySnap = await getDocs(payQ);
                if (!paySnap.empty) return alert("❌ ACTION BLOCKED: This Party has transaction history (Payments). Cannot delete.");

                // --- FIX ENDS HERE ---
            }

            else if (collectionName === 'accounts') {
                // Check if Account has Payments
                const payQ = query(
                    collection(db, 'payments'),
                    where("accountId", "==", id),
                    where("userId", "==", user.uid), // <--- Added this for safety too
                    limit(1)
                );
                const paySnap = await getDocs(payQ);
                if (!paySnap.empty) return alert("❌ ACTION BLOCKED: This Account has transactions. Cannot delete.");
            }

            else if (collectionName === 'products') {
                const prod = products.find(p => p.id === id);
                if (prod && (prod.currentStock > 0 || prod.currentStock < 0)) {
                    return alert("❌ ACTION BLOCKED: This item has stock remaining. Please clear stock (Stock Journal) before deleting.");
                }
            }

            // 3. LOG BEFORE DELETE
            try {
                const docSnap = await getDoc(doc(db, collectionName, id));
                if (docSnap.exists()) {
                    await logAuditActivity('DELETED', collectionName, id, docSnap.data());
                }
            } catch (le) { console.warn("Log skip during delete", le); }

            // 4. IF SAFE, DELETE
            await deleteDoc(doc(db, collectionName, id));

        } catch (e) {
            // This is where your error message was coming from
            alert("Error checking data: " + e.message);
        }
    };

