    // Handler for Clicking a Voucher in Ledger (Edit)
    const handleViewTransaction = async (docId, type) => {
        try {
            // Determine Collection
            let col = 'invoices';
            if (['payment', 'in', 'out', 'contra'].includes(type)) col = 'payments';
            if (type === 'journal') col = 'journal_vouchers';
            if (type === 'manufacturing' || type === 'stock_journal') col = 'stock_journals';

            const docRef = doc(db, col, docId);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                const data = { id: docSnap.id, ...docSnap.data() };

                // --- 🔒 SECURITY CHECK FOR DATA ENTRY 1 ---
                if (currentRole === 'data_entry_1') {
                    // 1. Ownership Check
                    if (data.createdBy !== user.uid) {
                        alert("⛔ ACCESS DENIED\n\nYou can only Edit transactions created by YOU.");
                        return;
                    }
                    // 2. Password Check
                    const pwd = prompt("🔒 Enter Password to Edit:");
                    if (!pwd || pwd.toLowerCase() !== 'abcd') return alert("❌ Wrong Password");
                }
                // ------------------------------------------

                setEditData(data);

                const actionMap = {
                    'purchase': 'Editing Purchase Invoice',
                    'sales': 'Editing Sales Invoice',
                    'payment': 'Editing Payment',
                    'journal': 'Editing Journal Voucher',
                    'manufacturing': 'Editing Manufacturing Voucher'
                };
                updateMyActivity(actionMap[data.type] || 'Viewing Transaction');

                if (activeModal) setModalStack(s => [...s, activeModal]);

                // Open correct modal
                if (col === 'invoices') setActiveModal(data.type === 'purchase' ? 'purchase' : 'sales');
                else if (col === 'payments') setActiveModal('payment');
                else if (col === 'journal_vouchers') {
                    // ✅ CHECK FOR HIDDEN (LINKED) JOURNAL
                    if (data.linkedStockJournalId) {
                        setToast({ type: 'info', title: 'Redirecting...', message: 'Opening Original Mfg Journal...' });
                        // Recursive call to open the PARENT Stock Journal
                        return handleViewTransaction(data.linkedStockJournalId, 'stock_journal');
                    }
                    setActiveModal('journal');
                }
                else if (col === 'stock_journals') setActiveModal('stock_journal');
            } else {
                alert("Document not found!");
            }
        } catch (error) {
            console.error("Error viewing transaction:", error);
        }
    };

