const StatisticsModal = ({ isOpen, onClose, onBack, zIndex, statsPeriod, voucherStats, masterStats, onDrillDown }) => {
    if (!isOpen) return null;

    const handleVoucherClick = (label) => {
        const typeMap = {
            'Sales': 'sales',
            'Purchase': 'purchase',
            'Receipt': 'receipt',
            'Payment': 'payment',
            'Contra': 'contra',
            'Journal': 'journal',
            'Stock Journal / Mfg': 'manufacturing'
        };
        if (typeMap[label]) onDrillDown('voucher', typeMap[label]);
    };

    const handleMasterClick = (label) => {
        const typeMap = {
            'Ledgers (Total)': 'daybook',
            'Parties': 'parties',
            'Cash/Bank': 'accounts',
            'Expenses': 'expenses',
            'Income Accounts': 'income_accounts',
            'Capital Accounts': 'capital_accounts',
            'Asset Accounts': 'asset_accounts',
            'Items (Products)': 'items',
            'Stock Groups': 'stock_groups',
            'Party Groups': 'party_groups',
            'Expense Groups': 'expense_groups',
            'Locations': 'locations',
            'Units': 'unit_manager',
            'Lots': 'lots',
            'Tax Rates': 'tax_rates',
            'Users': 'manage_users'
        };
        if (typeMap[label]) onDrillDown('master', typeMap[label]);
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            onBack={onBack}
            zIndex={zIndex}
            title="Statistics"
            maxWidth="max-w-6xl"
        >
            <div className="space-y-4">
                <div className="text-xs text-slate-500 flex justify-between items-center">
                    <span>Period: <span className="font-bold text-slate-700">{statsPeriod?.label}</span></span>
                    <span className="text-[10px] text-blue-500 font-bold italic">Click any row to view details</span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Left: Voucher Types */}
                    <div className="space-y-2">
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-wider">Types of Vouchers (Made)</div>
                        <div className="border rounded-lg overflow-hidden bg-white shadow-sm">
                            {voucherStats.items.map((item) => (
                                <div
                                    key={item.label}
                                    onClick={() => handleVoucherClick(item.label)}
                                    className="flex justify-between items-center px-4 py-2.5 text-sm border-b last:border-b-0 cursor-pointer hover:bg-blue-50 transition-colors group"
                                >
                                    <span className="text-slate-600 group-hover:text-blue-700 group-hover:font-bold transition-all">{item.label}</span>
                                    <span className="font-bold text-slate-900 bg-slate-100 group-hover:bg-blue-100 px-2 py-0.5 rounded min-w-[30px] text-center">{item.count}</span>
                                </div>
                            ))}
                            <div className="flex justify-between items-center px-4 py-3 text-sm font-bold bg-slate-50 border-t text-slate-800">
                                <span>Total Vouchers</span>
                                <span className="text-lg">{voucherStats.total}</span>
                            </div>
                        </div>
                        <div className="text-xs text-slate-500">Voucher Types Used: <span className="font-bold">{voucherStats.typeCount}</span></div>
                    </div>

                    {/* Right: Master Counts */}
                    <div className="space-y-2">
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-wider">Types of Accounts / Masters</div>
                        <div className="border rounded-lg overflow-hidden bg-white shadow-sm">
                            {masterStats.items.map((item) => (
                                <div
                                    key={item.label}
                                    onClick={() => handleMasterClick(item.label)}
                                    className="flex justify-between items-center px-4 py-2.5 text-sm border-b last:border-b-0 cursor-pointer hover:bg-blue-50 transition-colors group"
                                >
                                    <span className="text-slate-600 group-hover:text-blue-700 group-hover:font-bold transition-all">{item.label}</span>
                                    <span className="font-bold text-slate-900 bg-slate-100 group-hover:bg-blue-100 px-2 py-0.5 rounded min-w-[30px] text-center">{item.count}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </Modal>
    );
};

const highlightMenuShortcut = (label, sc) => {
    if (!label) return null;
    const shortcutChar = sc || label[0];
    const index = label.toLowerCase().indexOf(shortcutChar.toLowerCase());
    if (index === -1) return label;
    return (
        <>
            {label.substring(0, index)}
            <span className="tally-shortcut-key">{label[index]}</span>
            {label.substring(index + 1)}
        </>
    );
};

const MenuButton = ({ label, shortcut, onClick, className = "" }) => (
    <button onClick={onClick} className={`tally-item-btn ${className}`}>
        <span className="flex-1">{highlightMenuShortcut(label, shortcut)}</span>
    </button>
);

const MenuDropdown = ({ label, shortcut, children, activeSubMenu, setActiveSubMenu }) => {
    const isActive = activeSubMenu?.label === label;
    return (
        <div className="relative">
            <button
                onClick={() => setActiveSubMenu(isActive ? null : { label, children })}
                className={`tally-item-btn ${isActive ? 'active' : ''}`}
            >
                <span className="flex-1">{highlightMenuShortcut(label, shortcut)}</span>
                <ChevronRight size={14} className={isActive ? 'text-[#005994]' : 'text-slate-400'} />
            </button>
        </div>
    );
};

